// Lazy-loaded markdown renderer. react-markdown + remark-gfm pull a sizable
// chunk we don't need on first paint, so we split them into their own bundle
// and load only when an event description is actually rendered.

import { lazy, Suspense, type ComponentType, type ReactNode } from 'react';
import { CircularProgress, Box } from '@mui/material';

interface MarkdownComponentsMap {
  // Mirrors react-markdown's `components` prop without importing its types up-front.
  [tag: string]: ComponentType<Record<string, unknown> & { children?: ReactNode }>;
}

interface LazyMarkdownProps {
  children: string;
  components?: MarkdownComponentsMap;
}

const ReactMarkdownLazy = lazy(async () => {
  const [{ default: ReactMarkdown }, { default: remarkGfm }] = await Promise.all([
    import('react-markdown'),
    import('remark-gfm'),
  ]);
  // Wrap in a small adapter so callers don't have to deal with remarkPlugins.
  const Adapter = ({ children, components }: LazyMarkdownProps) => (
    <ReactMarkdown remarkPlugins={[remarkGfm]} components={components as never}>
      {children}
    </ReactMarkdown>
  );
  return { default: Adapter };
});

export function LazyMarkdown(props: LazyMarkdownProps) {
  return (
    <Suspense
      fallback={
        <Box sx={{ display: 'flex', justifyContent: 'center', py: 1 }}>
          <CircularProgress size={16} />
        </Box>
      }
    >
      <ReactMarkdownLazy {...props} />
    </Suspense>
  );
}
