import React from 'react';
import { useNavigate } from '@tanstack/react-router';
import { Box, Button, Card, CardActions, CardContent, Chip, Collapse, Divider, IconButton, List, ListItem, ListItemIcon, ListItemText, Typography } from '@mui/material';
import { LazyMarkdown } from '@/components/LazyMarkdown';
import { calculateDonationTotal } from '@/utils/eventCalculations';
import { logger } from '@/utils/logger';
import { EventResult } from '@/types/event.types';
import { RegisteredEventInfo } from '@/types/attendee.types';
import { AttendeeServices, AttendeeServicesError } from '@/api';
import { ApiComponentStateManager } from '@/lib/api-state';
import { initialStateData, StateData } from '@/store';
import { CallStatus, Roles } from '@/types/api.types';
import { StatusMessage } from '@/components/StatusMessage';
import { EventActionDialog } from '@/components/EventActionDialog';
import { GetUserRoles } from '@/utils/token';
import { UnixTimestampToReadableWithTimezone } from '@/utils/common';
import EventIcon from '@mui/icons-material/Event';
import LocationOnIcon from '@mui/icons-material/LocationOn';
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import LinkIcon from '@mui/icons-material/Link';
import PersonIcon from '@mui/icons-material/Person';
import AppRegistrationIcon from '@mui/icons-material/AppRegistration';
import CancelIcon from '@mui/icons-material/Cancel';
import EditIcon from '@mui/icons-material/Edit';
import VideocamIcon from '@mui/icons-material/Videocam';
import BusinessIcon from '@mui/icons-material/Business';
import InfoOutlinedIcon from '@mui/icons-material/InfoOutlined';
import RestaurantIcon from '@mui/icons-material/Restaurant';
import CurrencyRupeeIcon from '@mui/icons-material/CurrencyRupee';
import GroupIcon from '@mui/icons-material/Group';
import VolunteerActivismIcon from '@mui/icons-material/VolunteerActivism';
import VisibilityIcon from '@mui/icons-material/Visibility';
import { Pathname } from '@/constants/Routes';

interface EventCardProps {
    event: EventResult;
    registrationInfo?: RegisteredEventInfo | null;
    onRegistrationChange?: () => void;
    onEventEdit?: (eventId: string) => void;
    defaultCollapsed?: boolean;
}

// Custom markdown components: prevent transaction-id email autolinks; give
// paragraphs/lists/hr proper spacing so dense donation details render legibly.
const markdownComponents = {
    a: ({ href, children, ...props }: any) => {
        // Don't render as link if it looks like a transaction ID (contains @BKID or similar patterns)
        if (href && href.startsWith('mailto:') && (href.includes('@BKID') || href.includes('.ifsc.npci') || href.includes('.upi'))) {
            // Return plain text instead of link
            return <span>{children}</span>;
        }
        // Render normal links
        return <a href={href} {...props}>{children}</a>;
    },
    p: ({ children, ...props }: any) => (
        <p style={{ margin: '0 0 0.6em 0', lineHeight: 1.55 }} {...props}>{children}</p>
    ),
    ul: ({ children, ...props }: any) => (
        <ul style={{ margin: '0 0 0.6em 0', paddingLeft: '1.25em' }} {...props}>{children}</ul>
    ),
    ol: ({ children, ...props }: any) => (
        <ol style={{ margin: '0 0 0.6em 0', paddingLeft: '1.25em' }} {...props}>{children}</ol>
    ),
    li: ({ children, ...props }: any) => (
        <li style={{ marginBottom: '0.25em' }} {...props}>{children}</li>
    ),
    hr: ({ ...props }: any) => (
        <hr style={{ border: 0, borderTop: '1px solid rgba(0,0,0,0.12)', margin: '0.75em 0' }} {...props} />
    ),
};

export const EventCard: React.FC<EventCardProps> = ({ event, registrationInfo = null, onRegistrationChange, onEventEdit, defaultCollapsed = false }) => {
    const [expanded] = React.useState(!defaultCollapsed);
    const navigate = useNavigate();
    const [registerState, setRegisterState] = React.useState<StateData<boolean>>(initialStateData<boolean>());
    const [cancelState, setCancelState] = React.useState<StateData<boolean>>(initialStateData<boolean>());
    const [updateState, setUpdateState] = React.useState<StateData<boolean>>(initialStateData<boolean>());
    const [openCancelDialog, setOpenCancelDialog] = React.useState<boolean>(false);
    const [openRegistrationDialog, setOpenRegistrationDialog] = React.useState<boolean>(false);
    const [openUpdateDialog, setOpenUpdateDialog] = React.useState<boolean>(false);
    const [localRegistrationInfo, setLocalRegistrationInfo] = React.useState(registrationInfo);
    const userRoles = GetUserRoles();

    // Update local state when registrationInfo prop changes
    React.useEffect(() => {
        setLocalRegistrationInfo(registrationInfo);
    }, [registrationInfo]);

    // Get food options from event's food field (comma-separated) - EXACTLY as configured
    const foodOptions = React.useMemo(() => {
        if (event.food && event.isFoodEnabled) {
            return event.food.split(',').map((opt: string) => opt.trim()).filter((opt: string) => opt.length > 0);
        }
        return [];
    }, [event.food, event.isFoodEnabled]);

    // Memoized donation total from user's registration
    const donationTotal = React.useMemo(
        () => calculateDonationTotal(localRegistrationInfo?.donation),
        [localRegistrationInfo?.donation]
    );

    // Check if user is Admin or SuperAdmin for edit access
    const canEditEvent = React.useMemo(() => {
        return userRoles.includes(Roles.Admin) || userRoles.includes(Roles.SuperAdmin);
    }, [userRoles]);

    const getEventStatus = () => {
        const now = new Date();
        // Handle Unix timestamp in milliseconds
        const startDate = new Date(event.startDateTime);
        const endDate = new Date(event.endDateTime);

        if (now < startDate) {
            return { label: 'Upcoming', color: 'primary' as const };
        } else if (now >= startDate && now <= endDate) {
            return { label: 'Live', color: 'success' as const };
        } else {
            return { label: 'Completed', color: 'default' as const };
        }
    };

    const status = getEventStatus();

    const handleRegisterClick = () => {
        setOpenRegistrationDialog(true);
    };

    const handleRegisterConfirm = async (foodPreference: string, headCount: number) => {
        await handleRegisterWithFood(foodPreference, headCount);
        setOpenRegistrationDialog(false);
    };

    const handleRegisterWithFood = async (food: string, headCount: number) => {
        try {
            const hasExistingRegistration = Boolean(localRegistrationInfo);
            const requestPromise = hasExistingRegistration
                ? AttendeeServices.UpdateRegistration(event.id.toString(), food, headCount)
                : AttendeeServices.RegisterAttendee(event.id.toString(), food, headCount);

            ApiComponentStateManager(requestPromise, setRegisterState);

            try {
                const response = await requestPromise;
                if (response.data && response.data.status >= 200 && response.data.status < 300) {
                    const updatedData = response.data.result;
                    setLocalRegistrationInfo(prev => {
                        if (updatedData) {
                            return {
                                eventId: updatedData.eventId ?? prev?.eventId ?? event.id.toString(),
                                foodPreference: updatedData.foodPreference ?? food,
                                headCount: updatedData.headCount ?? headCount,
                                registeredAt: updatedData.registeredAt ?? prev?.registeredAt ?? Date.now(),
                            };
                        }

                        if (prev) {
                            return {
                                ...prev,
                                foodPreference: food,
                                headCount: headCount,
                            };
                        }

                        return {
                            eventId: event.id.toString(),
                            foodPreference: food,
                            headCount: headCount,
                            registeredAt: Date.now(),
                        };
                    });

                    if (onRegistrationChange) {
                        onRegistrationChange();
                    }
                }
            } catch (error) {
                logger.error('EventCard', 'Registration API call failed', error);
            }
        } catch (error) {
            logger.error('EventCard', 'Error registering for event', error);
        }
    };

    const handleCancelClick = () => {
        setOpenCancelDialog(true);
    };

    const handleCancelConfirm = async () => {
        setOpenCancelDialog(false);
        
        try {
            // Update registration with headcount 0 and null food preference
            const updatePromise = AttendeeServices.UpdateRegistration(event.id.toString(), '', 0);
            ApiComponentStateManager(updatePromise, setCancelState);
            
            // Wait for cancel to complete and update local state
            try {
                const response = await updatePromise;
                if (response.data && response.data.status >= 200 && response.data.status < 300) {
                    // Update local registration info - set count to 0 and clear food preference
                    const updatedData = response.data.result;
                    setLocalRegistrationInfo(prev => prev ? {
                        ...prev,
                        foodPreference: updatedData.foodPreference || '',
                        headCount: updatedData.headCount ?? 0
                    } : prev);
                }
            } catch (error) {
                logger.error('EventCard', 'Cancel registration API call failed', error);
            }
            
            // Call the callback to refresh registered events on success
            setTimeout(() => {
                if (cancelState.status === CallStatus.Success && onRegistrationChange) {
                    onRegistrationChange();
                }
            }, 1000);
        } catch (error) {
            logger.error('EventCard', 'Error canceling registration', error);
        }
    };

    const handleUpdateClick = () => {
        setOpenUpdateDialog(true);
    };

    const handleUpdateConfirm = async (foodPreference: string, headCount: number) => {
        setOpenUpdateDialog(false);
        
        try {
            const updatePromise = AttendeeServices.UpdateRegistration(event.id.toString(), foodPreference, headCount);
            ApiComponentStateManager(updatePromise, setUpdateState);
            
            // Wait for update to complete and update local state with API response
            try {
                const response = await updatePromise;
                if (response.data && response.data.status >= 200 && response.data.status < 300) {
                    // Update local registration info with response data
                    const updatedData = response.data.result;
                    setLocalRegistrationInfo(prev => prev ? {
                        ...prev,
                        foodPreference: updatedData.foodPreference,
                        headCount: updatedData.headCount
                    } : prev);
                }
            } catch (error) {
                logger.error('EventCard', 'Update API call failed', error);
            }
            
            // Call the callback to refresh registered events on success
            setTimeout(() => {
                if (updateState.status === CallStatus.Success && onRegistrationChange) {
                    onRegistrationChange();
                }
            }, 1000);
        } catch (error) {
            logger.error('EventCard', 'Error updating registration', error);
        }
    };

    const handleEdit = () => {
        if (onEventEdit) {
            onEventEdit(event.id.toString());
        }
    };

    const handleTitleClick = () => {
        navigate({ to: `${Pathname.Events_View}/${event.id}` as string });
    };

    const isEventUpcoming = () => {
        return status.label === 'Upcoming';
    };

    return (
        <>
        <Card sx={{
            marginBottom: 2,
            borderRadius: 2,
            border: '1px solid',
            borderColor: 'divider',
            borderLeft: '4px solid',
            borderLeftColor: status.label === 'Upcoming' ? 'primary.main' : status.label === 'Live' ? 'success.main' : 'text.disabled',
            boxShadow: 'none',
            transition: 'box-shadow 0.2s',
            '&:hover': { boxShadow: 2 },
        }}>
            <CardContent sx={{ pb: 1 }}>
                {/* Title + Edit */}
                <Box sx={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', mb: 0.5 }}>
                    <Box sx={{ flex: 1, minWidth: 0 }}>
                        <Typography 
                            variant="h6" 
                            onClick={handleTitleClick}
                            sx={{
                                fontWeight: 600, 
                                cursor: 'pointer',
                                color: 'primary.main',
                                '&:hover': {
                                    textDecoration: 'underline',
                                    color: 'primary.dark'
                                }
                            }}
                        >
                            {event.title}
                        </Typography>
                    </Box>
                    {canEditEvent && (
                        <IconButton
                            onClick={handleEdit}
                            size="small"
                            title="Edit Event"
                            sx={{
                                color: '#fff',
                                bgcolor: 'primary.main',
                                width: 32,
                                height: 32,
                                flexShrink: 0,
                                ml: 1,
                                '&:hover': { bgcolor: 'primary.dark' },
                            }}
                        >
                            <EditIcon sx={{ fontSize: '1rem' }} />
                        </IconButton>
                    )}
                </Box>

                {/* Status chip */}
                <Box sx={{ mb: 1 }}>
                    <Chip
                        label={status.label}
                        color={status.color}
                        size="small"
                        variant={status.label === 'Live' ? 'filled' : 'outlined'}
                        sx={{ fontSize: '0.7rem', height: 22, fontWeight: 500, ...(status.label === 'Live' && { color: '#fff !important', '& .MuiChip-label': { color: '#fff' } }) }}
                    />
                </Box>

                {/* Meta info — only shown when collapsed (avoids duplicating the expanded list) */}
                {!expanded && (
                <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr' }, gap: 0.5, mb: 1 }}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                        <AccessTimeIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                        <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                            {UnixTimestampToReadableWithTimezone(event.startDateTime)}
                        </Typography>
                    </Box>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                        <LocationOnIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                        <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                            {event.location}
                        </Typography>
                    </Box>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                        {event.isOnlineMeeting ? (
                            <VideocamIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                        ) : (
                            <BusinessIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                        )}
                        <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                            {event.isOnlineMeeting ? 'Online Meeting' : 'In-Person Event'}
                        </Typography>
                    </Box>
                </Box>
                )}

                {/* Collapsed: View Details button */}
                {!expanded && (
                    <Box sx={{ mt: 0.5 }}>
                        <Divider sx={{ mb: 1, borderStyle: 'dashed' }} />
                        <Button
                            size="small"
                            variant="contained"
                            color="primary"
                            onClick={handleTitleClick}
                            startIcon={<VisibilityIcon fontSize="small" />}
                            sx={{ textTransform: 'capitalize', borderRadius: 2 }}
                        >
                            View Details
                        </Button>
                    </Box>
                )}

                <Collapse in={expanded} timeout="auto">
                <List dense={true}>
                    <ListItem sx={{ py: 0.5 }}>
                        <ListItemIcon sx={{ minWidth: '36px' }}>
                            <AccessTimeIcon fontSize="small" />
                        </ListItemIcon>
                        <ListItemText>
                            <Typography variant="body2">
                                <strong>Start:</strong> {UnixTimestampToReadableWithTimezone(event.startDateTime)}
                            </Typography>
                        </ListItemText>
                    </ListItem>
                    <ListItem sx={{ py: 0.5 }}>
                        <ListItemIcon sx={{ minWidth: '36px' }}>
                            <EventIcon fontSize="small" />
                        </ListItemIcon>
                        <ListItemText>
                            <Typography variant="body2">
                                <strong>End:</strong> {UnixTimestampToReadableWithTimezone(event.endDateTime)}
                            </Typography>
                        </ListItemText>
                    </ListItem>
                    <ListItem sx={{ py: 0.5 }}>
                        <ListItemIcon sx={{ minWidth: '36px' }}>
                            <PersonIcon fontSize="small" />
                        </ListItemIcon>
                        <ListItemText>
                            <Typography variant="body2">
                                <strong>Contact:</strong> {event.contact}
                            </Typography>
                        </ListItemText>
                    </ListItem>
                    <ListItem sx={{ py: 0.5 }}>
                        <ListItemIcon sx={{ minWidth: '36px' }}>
                            <LocationOnIcon fontSize="small" />
                        </ListItemIcon>
                        <ListItemText>
                            <Typography variant="body2">
                                {event.locationLink ? (
                                    <a 
                                        href={event.locationLink} 
                                        target="_blank" 
                                        rel="noopener noreferrer"
                                        style={{ color: 'var(--link-color)', textDecoration: 'none' }}
                                    >
                                        {event.location}
                                    </a>
                                ) : (
                                    event.location
                                )}
                            </Typography>
                        </ListItemText>
                    </ListItem>
                    {event.details && (
                        <ListItem sx={{ py: 0.5, alignItems: 'flex-start' }}>
                            <ListItemIcon sx={{ minWidth: '36px', mt: 0.5 }}>
                                <InfoOutlinedIcon fontSize="small" />
                            </ListItemIcon>
                            <ListItemText>
                                <Typography
                                    variant="body2"
                                    color="text.secondary"
                                    component="div"
                                    sx={{
                                        '& p': { margin: '0.25em 0' },
                                        '& ul, & ol': { paddingLeft: '1.5em', margin: '0.25em 0' },
                                        '& li': { marginBottom: '0.125em' },
                                        '& h1, & h2, & h3, & h4, & h5, & h6': { margin: '0.25em 0 0.125em 0', fontWeight: 600 },
                                        '& code': { backgroundColor: 'rgba(0,0,0,0.05)', padding: '0.125em 0.25em', borderRadius: '3px', fontSize: '0.9em' },
                                        '& pre': { backgroundColor: 'rgba(0,0,0,0.05)', padding: '0.5em', borderRadius: '4px', overflow: 'auto' },
                                        '& a': { color: 'primary.main', textDecoration: 'underline' },
                                        '& blockquote': { borderLeft: '3px solid rgba(0,0,0,0.2)', paddingLeft: '0.75em', margin: '0.25em 0', fontStyle: 'italic' },
                                    }}
                                >
                                    <LazyMarkdown components={markdownComponents}>
                                        {event.details}
                                    </LazyMarkdown>
                                </Typography>
                            </ListItemText>
                        </ListItem>
                    )}
                    <ListItem sx={{ py: 0.5 }}>
                        <ListItemIcon sx={{ minWidth: '36px' }}>
                            {event.isOnlineMeeting ? <VideocamIcon fontSize="small" /> : <BusinessIcon fontSize="small" />}
                        </ListItemIcon>
                        <ListItemText>
                            <Typography variant="body2">
                                {event.isOnlineMeeting ? 'Online Meeting' : 'In-Person Event'}
                            </Typography>
                        </ListItemText>
                    </ListItem>
                    {event.isFoodEnabled && event.food && (
                        <ListItem sx={{ py: 0.5 }}>
                            <ListItemIcon sx={{ minWidth: '36px' }}>
                                <RestaurantIcon fontSize="small" />
                            </ListItemIcon>
                            <ListItemText>
                                <Typography variant="body2">
                                    <strong>Food Options:</strong> {event.food}
                                </Typography>
                            </ListItemText>
                        </ListItem>
                    )}
                    {event.donation && (
                        <ListItem sx={{ py: 0.5, alignItems: 'flex-start' }}>
                            <ListItemIcon sx={{ minWidth: '36px', mt: 0.5 }}>
                                <CurrencyRupeeIcon fontSize="small" sx={{ color: 'secondary.main' }} />
                            </ListItemIcon>
                            <ListItemText>
                                <Typography 
                                    variant="body2" 
                                    component="div"
                                    sx={{
                                        '& p': { margin: '0.25em 0' },
                                        '& ul, & ol': { paddingLeft: '1.5em', margin: '0.25em 0' },
                                        '& li': { marginBottom: '0.125em' },
                                        '& h1, & h2, & h3, & h4, & h5, & h6': { 
                                            margin: '0.25em 0 0.125em 0', 
                                            fontWeight: 600,
                                            fontSize: '0.9em'
                                        },
                                        '& code': { 
                                            backgroundColor: 'rgba(0, 0, 0, 0.05)', 
                                            padding: '0.125em 0.25em', 
                                            borderRadius: '3px',
                                            fontSize: '0.85em'
                                        },
                                        '& pre': { 
                                            backgroundColor: 'rgba(0, 0, 0, 0.05)', 
                                            padding: '0.5em', 
                                            borderRadius: '4px',
                                            overflow: 'auto',
                                            fontSize: '0.85em'
                                        },
                                        '& a': { color: 'primary.main', textDecoration: 'underline' },
                                        '& blockquote': { 
                                            borderLeft: '3px solid rgba(0, 0, 0, 0.2)', 
                                            paddingLeft: '0.75em', 
                                            margin: '0.25em 0',
                                            fontStyle: 'italic'
                                        }
                                    }}
                                >
                                    <strong>Donation Info:</strong>
                                    <LazyMarkdown components={markdownComponents}>
                                        {event.donation}
                                    </LazyMarkdown>
                                </Typography>
                                {event.donationLink && (
                                    <Button
                                        size="small"
                                        variant="contained"
                                        href={event.donationLink}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        sx={{ 
                                            mt: 0.5, 
                                            textTransform: 'none',
                                            backgroundColor: 'secondary.main',
                                            color: 'white',
                                            '&:hover': {
                                                backgroundColor: 'secondary.dark'
                                            }
                                        }}
                                        startIcon={<VolunteerActivismIcon sx={{ color: 'white' }} />}
                                    >
                                        Donate Here
                                    </Button>
                                )}
                            </ListItemText>
                        </ListItem>
                    )}
                </List>

                {/* Registration Details Section */}
                {localRegistrationInfo && (
                    <>
                        <Divider sx={{ my: 1, borderStyle: 'dashed' }} />
                        <Typography variant="subtitle2" sx={{ px: 2, mb: 1, color: 'success.main', fontWeight: 600 }}>
                            ✓ Your details
                        </Typography>
                        <List dense sx={{ py: 0 }}>
                            {localRegistrationInfo.headCount > 0 && (
                                <ListItem sx={{ py: 0.5 }}>
                                    <ListItemIcon sx={{ minWidth: '36px' }}>
                                        <GroupIcon fontSize="small" color="primary" />
                                    </ListItemIcon>
                                    <ListItemText>
                                        <Typography variant="body2">
                                            <strong>Headcount:</strong> {localRegistrationInfo.headCount} {localRegistrationInfo.headCount === 1 ? 'person' : 'people'}
                                        </Typography>
                                    </ListItemText>
                                </ListItem>
                            )}
                            {localRegistrationInfo.foodPreference && (
                                <ListItem sx={{ py: 0.5 }}>
                                    <ListItemIcon sx={{ minWidth: '36px' }}>
                                        <RestaurantIcon fontSize="small" color="primary" />
                                    </ListItemIcon>
                                    <ListItemText>
                                        <Typography variant="body2">
                                            <strong>Your Food Preference:</strong> {localRegistrationInfo.foodPreference}
                                        </Typography>
                                    </ListItemText>
                                </ListItem>
                            )}
                            {localRegistrationInfo.donation && donationTotal > 0 && (
                                <ListItem sx={{ py: 0.5, alignItems: 'flex-start' }}>
                                    <ListItemIcon sx={{ minWidth: '36px', mt: 0.5 }}>
                                        <CurrencyRupeeIcon fontSize="small" sx={{ color: 'secondary.main' }} />
                                    </ListItemIcon>
                                    <ListItemText>
                                        <Typography variant="body2" sx={{ mb: 0.5 }}>
                                            <strong>Your Donation:</strong>
                                        </Typography>
                                        {localRegistrationInfo.donation.split(',').map((donation, index) => {
                                            const [amount, ref] = donation.trim().split('@');
                                            return (
                                                <Typography 
                                                    key={index} 
                                                    variant="body2" 
                                                    sx={{ 
                                                        fontFamily: 'monospace',
                                                        fontSize: '0.875rem',
                                                        ml: 1,
                                                        color: 'text.secondary'
                                                    }}
                                                >
                                                    ₹{amount} (Ref: {ref})
                                                </Typography>
                                            );
                                        })}
                                        <Typography 
                                            variant="body2" 
                                            sx={{ 
                                                color: 'secondary.main',
                                                mt: 0.5,
                                                ml: 1
                                            }}
                                        >
                                            Total: ₹{donationTotal}
                                        </Typography>
                                    </ListItemText>
                                </ListItem>
                            )}
                        </List>
                    </>
                )}
                </Collapse>
            </CardContent>
            <Collapse in={expanded} timeout="auto">
            <Divider sx={{ borderStyle: 'dashed' }} />
            <CardActions disableSpacing sx={{ py: 1, justifyContent: 'space-between', flexWrap: 'wrap', gap: 1 }}>
                <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap', alignItems: 'center', justifyContent: 'space-between', width: '100%' }}>
                    <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                        {/* Registration Button (only show for upcoming events with open registration) */}
                        {isEventUpcoming() && event.isRegistrationEnabled && (
                            (localRegistrationInfo && localRegistrationInfo.headCount > 0) ? (
                                // Already registered with headcount > 0 - show cancel and update buttons
                                cancelState.status !== CallStatus.Success && (
                                    <>
                                        {!event.isCheckinEnabled && (
                                            <Button
                                                variant="contained"
                                                size="medium"
                                                startIcon={<EditIcon />}
                                                onClick={handleUpdateClick}
                                                disabled={updateState.status === CallStatus.InProgress}
                                                color="primary"
                                                sx={{ 
                                                    textTransform: 'none', 
                                                    fontSize: '0.875rem', 
                                                    fontWeight: 500
                                                }}
                                            >
                                                {updateState.status === CallStatus.InProgress ? 'Updating...' : 'Update Registration'}
                                            </Button>
                                        )}
                                        <Button
                                            variant="outlined"
                                            size="medium"
                                            startIcon={<CancelIcon sx={{ color: 'error.main' }} />}
                                            onClick={handleCancelClick}
                                            disabled={cancelState.status === CallStatus.InProgress}
                                            color="error"
                                            sx={{ 
                                                textTransform: 'none', 
                                                fontSize: '0.875rem', 
                                                fontWeight: '500'
                                            }}
                                        >
                                            {cancelState.status === CallStatus.InProgress ? 'Canceling...' : 'Cancel Registration'}
                                        </Button>
                                    </>
                                )
                            ) : event.registrationLink ? (
                                // External registration link
                                <Button
                                    variant="contained"
                                    size="medium"
                                    startIcon={<AppRegistrationIcon />}
                                    href={event.registrationLink}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    sx={{ textTransform: 'none', fontSize: '0.875rem', fontWeight: 500 }}
                                >
                                    Register
                                </Button>
                            ) : (
                                // API registration - show for new registrations or re-registrations after headcount 0
                                registerState.status !== CallStatus.Success && (
                                    <Button
                                        variant="contained"
                                        size="medium"
                                        startIcon={<AppRegistrationIcon />}
                                        onClick={handleRegisterClick}
                                        disabled={registerState.status === CallStatus.InProgress}
                                        sx={{ textTransform: 'none', fontSize: '0.875rem', fontWeight: 500 }}
                                    >
                                        {registerState.status === CallStatus.InProgress ? 'Registering...' : 'Register'}
                                    </Button>
                                )
                            )
                        )}
                        
                        {/* Registration Disabled Message */}
                        {isEventUpcoming() && !event.isRegistrationEnabled && (
                            <Button
                                variant="outlined"
                                size="medium"
                                disabled
                                sx={{
                                    textTransform: 'none', 
                                    fontSize: '0.875rem', 
                                    fontWeight: 500,
                                    color: 'error.main',
                                    borderColor: 'error.main'
                                }}
                            >
                                Registration Disabled
                            </Button>
                        )}
                        
                        {/* Event Link Button (only show if not used for registration) */}
                        {event.registrationLink && !isEventUpcoming() && (
                            <Button
                                variant="outlined"
                                size="small"
                                startIcon={<LinkIcon fontSize="small" />}
                                href={event.registrationLink}
                                target="_blank"
                                rel="noopener noreferrer"
                                sx={{ textTransform: 'none', fontSize: '0.75rem' }}
                            >
                                Event Link
                            </Button>
                        )}
                    </div>
                </div>
                
                {/* Registration Status Message */}
                {registerState.status !== CallStatus.NotStarted && (
                    <div style={{ width: '100%', marginTop: '8px' }}>
                        <StatusMessage
                            notStartedMessage=""
                            successMessage="Successfully registered for the event!"
                            failureMessage={AttendeeServicesError.RegisterAttendeeError(registerState.httpStatus)}
                            currentStatus={registerState.status}
                            correlationId={registerState.correlationId}
                        />
                    </div>
                )}

                {/* Cancellation Status Message */}
                {cancelState.status !== CallStatus.NotStarted && (
                    <div style={{ width: '100%', marginTop: '8px' }}>
                        <StatusMessage
                            notStartedMessage=""
                            successMessage="Registration canceled successfully!"
                            failureMessage={AttendeeServicesError.CancelRegistrationError(cancelState.httpStatus)}
                            currentStatus={cancelState.status}
                            correlationId={cancelState.correlationId}
                        />
                    </div>
                )}

                {/* Update Status Message */}
                {updateState.status !== CallStatus.NotStarted && (
                    <div style={{ width: '100%', marginTop: '8px' }}>
                        <StatusMessage
                            notStartedMessage=""
                            successMessage="Registration updated successfully!"
                            failureMessage={AttendeeServicesError.UpdateRegistrationError(updateState.httpStatus)}
                            currentStatus={updateState.status}
                            correlationId={updateState.correlationId}
                        />
                    </div>
                )}
            </CardActions>
            </Collapse>
        </Card>

        {/* Cancel Registration Dialog */}
        <EventActionDialog
            open={openCancelDialog}
            actionType="cancel"
            userName="your registration"
            eventTitle={event.title}
            onClose={() => setOpenCancelDialog(false)}
            onConfirm={handleCancelConfirm}
            isLoading={cancelState.status === CallStatus.InProgress}
        />

        {/* Registration Dialog */}
        <EventActionDialog
            open={openRegistrationDialog}
            actionType="register"
            userName="yourself"
            eventTitle={event.title}
            onClose={() => setOpenRegistrationDialog(false)}
            onConfirm={handleRegisterConfirm}
            isFoodEnabled={event.isFoodEnabled}
            isAccompanyEnabled={event.isAccompanyEnabled}
            foodOptions={foodOptions}
            initialCount={1}
            isLoading={registerState.status === CallStatus.InProgress}
        />

        {/* Update Registration Dialog */}
        <EventActionDialog
            open={openUpdateDialog}
            actionType="update"
            userName="your registration"
            eventTitle={event.title}
            onClose={() => setOpenUpdateDialog(false)}
            onConfirm={handleUpdateConfirm}
            isFoodEnabled={event.isFoodEnabled}
            isAccompanyEnabled={event.isAccompanyEnabled}
            foodOptions={foodOptions}
            initialFoodPreference={localRegistrationInfo?.foodPreference || ''}
            initialCount={localRegistrationInfo?.headCount ?? 1}
            isLoading={updateState.status === CallStatus.InProgress}
        />
    </>
    );
};